        )
        return {"service": "gmail", "status": resp.status_code, "data": resp.json() if resp.status_code == 200 else resp.text}
    except Exception as e:
        return {"service": "gmail", "error": str(e)}

def contacts_search_leo():
    """人事部：查询Leo"""
    try:
        resp = requests.post(
            "http://localhost:38087/contacts/search",
            json={"query": "Leo"},
            timeout=30
        )
        return {"service": "contacts_leo", "status": resp.status_code, "data": resp.json() if resp.status_code == 200 else resp.text}
    except Exception as e:
        return {"service": "contacts_leo", "error": str(e)}

def contacts_search_mike():
    """人事部：查询Mike"""
    try:
        resp = requests.post(
            "http://localhost:38087/contacts/search",
            json={"query": "Mike"},
            timeout=30
        )
        return {"service": "contacts_mike", "status": resp.status_code, "data": resp.json() if resp.status_code == 200 else resp.text}
    except Exception as e:
        return {"service": "contacts_mike", "error": str(e)}

# 并行执行
with ThreadPoolExecutor(max_workers=3) as executor:
    futures = {
        "gmail": executor.submit(gmail_search),
        "leo": executor.submit(contacts_search_leo),
        "mike": executor.submit(contacts_search_mike)
    }
    results = {k: v.result() for k, v in futures.items()}

print("=== 第一阶段检索结果 ===")
for k, v in results.items():
    print(f"\n[{k}]")
    print(v)
